import{_ as e,o as n,c as a,ag as t}from"./chunks/framework.BbyMWZAR.js";const u=JSON.parse('{"title":"HTTP 报文的组成与常见 Header","description":"","frontmatter":{"title":"HTTP 报文的组成与常见 Header","difficulty":"easy","tags":["HTTP","报文","Header"],"estimate":15},"headers":[],"relativePath":"domains/browser/qa/qa-12-http-message.md","filePath":"domains/browser/qa/qa-12-http-message.md","lastUpdated":1783504823000}'),i={name:"domains/browser/qa/qa-12-http-message.md"};function r(l,s,d,o,p,c){return n(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="问答-12-入门-http-报文的组成与常见-header" tabindex="-1">问答 12（入门）：HTTP 报文的组成与常见 Header <a class="header-anchor" href="#问答-12-入门-http-报文的组成与常见-header" aria-label="Permalink to &quot;问答 12（入门）：HTTP 报文的组成与常见 Header&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>HTTP 请求 / 响应报文由哪些部分组成？请写出格式，并列举常见请求头和响应头及其作用。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>报文结构</strong></p><p>请求报文：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/user?id=1 HTTP/1.1        &lt;- 请求行：Method SP Path SP Version</span></span>
<span class="line"><span>Host: example.com                  &lt;- Header 区（多行 key: value）</span></span>
<span class="line"><span>User-Agent: Mozilla/5.0</span></span>
<span class="line"><span>Accept: application/json</span></span>
<span class="line"><span>Cookie: sid=abc</span></span>
<span class="line"><span>Content-Type: application/json</span></span>
<span class="line"><span>Content-Length: 27</span></span>
<span class="line"><span>                                   &lt;- 空行（\\r\\n）标志 Header 结束</span></span>
<span class="line"><span>{&quot;name&quot;:&quot;foo&quot;,&quot;age&quot;:18}            &lt;- Body（可选）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>响应报文：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTP/1.1 200 OK                    &lt;- 状态行：Version SP Status SP Reason</span></span>
<span class="line"><span>Content-Type: application/json     &lt;- Header</span></span>
<span class="line"><span>Content-Length: 42</span></span>
<span class="line"><span>Cache-Control: max-age=60</span></span>
<span class="line"><span>Set-Cookie: sid=abc; HttpOnly</span></span>
<span class="line"><span>                                   &lt;- 空行</span></span>
<span class="line"><span>{&quot;ok&quot;:true,&quot;data&quot;:{&quot;id&quot;:1}}         &lt;- Body</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ul><li><strong>起始行</strong>：请求是 <code>Method Path Version</code>，响应是 <code>Version Status Reason</code>。</li><li><strong>Header 行</strong>：<code>Name: Value</code>，大小写不敏感（HTTP/2 强制小写）。</li><li><strong>空行</strong>：<code>\\r\\n\\r\\n</code>，标识 Header 结束。</li><li><strong>Body</strong>：请求 / 响应主体，可为空；由 <code>Content-Length</code> 或 <code>Transfer-Encoding: chunked</code> 界定长度。</li></ul><p><strong>常见请求头</strong></p><table tabindex="0"><thead><tr><th>头</th><th>作用</th></tr></thead><tbody><tr><td><code>Host</code></td><td>目标主机名（HTTP/1.1 必填），支持虚拟主机</td></tr><tr><td><code>User-Agent</code></td><td>客户端标识</td></tr><tr><td><code>Accept</code> / <code>Accept-Language</code> / <code>Accept-Encoding</code></td><td>内容协商（想要什么类型 / 语言 / 编码）</td></tr><tr><td><code>Cookie</code></td><td>携带 cookie</td></tr><tr><td><code>Authorization</code></td><td><code>Basic base64(...)</code> / <code>Bearer &lt;token&gt;</code></td></tr><tr><td><code>Referer</code></td><td>来源页 URL（注意规范拼错的 <code>Referer</code>）</td></tr><tr><td><code>Origin</code></td><td>请求来源（协议+域+端口），CORS 校验用</td></tr><tr><td><code>Content-Type</code></td><td>Body 类型：<code>application/json</code>、<code>multipart/form-data</code> 等</td></tr><tr><td><code>Content-Length</code></td><td>Body 字节数</td></tr><tr><td><code>If-None-Match</code> / <code>If-Modified-Since</code></td><td>协商缓存</td></tr><tr><td><code>Range</code></td><td>断点续传 / 视频拖动</td></tr><tr><td><code>Connection</code></td><td><code>keep-alive</code> / <code>close</code></td></tr><tr><td><code>Upgrade</code></td><td>协议升级（WebSocket）</td></tr><tr><td><code>X-Requested-With</code></td><td>jQuery 时代标记 XHR</td></tr></tbody></table><p><strong>常见响应头</strong></p><table tabindex="0"><thead><tr><th>头</th><th>作用</th></tr></thead><tbody><tr><td><code>Content-Type</code></td><td>响应类型（还带 <code>; charset=utf-8</code>）</td></tr><tr><td><code>Content-Length</code> / <code>Transfer-Encoding: chunked</code></td><td>长度标识</td></tr><tr><td><code>Cache-Control</code> / <code>Expires</code> / <code>ETag</code> / <code>Last-Modified</code></td><td>缓存控制</td></tr><tr><td><code>Set-Cookie</code></td><td>下发 cookie</td></tr><tr><td><code>Location</code></td><td>3xx 重定向目标</td></tr><tr><td><code>Access-Control-Allow-Origin</code> / <code>Allow-*</code></td><td>CORS 授权</td></tr><tr><td><code>Content-Encoding</code></td><td>压缩方式：gzip / br / deflate</td></tr><tr><td><code>Content-Disposition</code></td><td>浏览器如何处理响应（inline / attachment 下载）</td></tr><tr><td><code>Vary</code></td><td>缓存 key 附加维度</td></tr><tr><td><code>Strict-Transport-Security</code></td><td>HSTS</td></tr><tr><td><code>Content-Security-Policy</code></td><td>CSP 策略</td></tr><tr><td><code>X-Content-Type-Options: nosniff</code></td><td>禁止 MIME 嗅探</td></tr><tr><td><code>X-Frame-Options</code> / <code>frame-ancestors</code></td><td>防点击劫持</td></tr><tr><td><code>Referrer-Policy</code></td><td>控制 Referer 泄漏程度</td></tr><tr><td><code>Server</code></td><td>服务端软件（安全上建议隐藏）</td></tr><tr><td><code>Alt-Svc</code></td><td>协议升级提示（HTTP/3）</td></tr></tbody></table><h2 id="追问-1-content-length-和-transfer-encoding-chunked-能同时出现吗" tabindex="-1">追问 1：<code>Content-Length</code> 和 <code>Transfer-Encoding: chunked</code> 能同时出现吗？ <a class="header-anchor" href="#追问-1-content-length-和-transfer-encoding-chunked-能同时出现吗" aria-label="Permalink to &quot;追问 1：\`Content-Length\` 和 \`Transfer-Encoding: chunked\` 能同时出现吗？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>规范禁止同时出现。若同时出现，根据 RFC 7230，接收方<strong>必须以 <code>Transfer-Encoding</code> 为准并忽略 <code>Content-Length</code></strong>，或视为错误。</li><li>历史上曾出现 <strong>HTTP Request Smuggling</strong> 漏洞：前后代理对二者解析不同，攻击者可以塞进两条请求，前端代理认一个，后端认另一个，导致越权。</li><li>修复： <ul><li>服务端要严格拒绝同时含二者的请求。</li><li>Nginx / CDN 前端网关做统一规范化。</li><li>应用层不要手动拼字节流。</li></ul></li><li><code>chunked</code> 用于流式响应（如 SSE、大文件下载），格式为一段段 <code>hex\\r\\n&lt;data&gt;\\r\\n</code>，以 <code>0\\r\\n\\r\\n</code> 结束。</li></ul><h2 id="追问-2-referer-和-origin-有什么区别" tabindex="-1">追问 2：<code>Referer</code> 和 <code>Origin</code> 有什么区别？ <a class="header-anchor" href="#追问-2-referer-和-origin-有什么区别" aria-label="Permalink to &quot;追问 2：\`Referer\` 和 \`Origin\` 有什么区别？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>Referer</strong>：完整来源 URL（含 path / query）。历史悠久，很多接口用它做防盗链、来源统计。</li><li><strong>Origin</strong>：只包含协议 + 域 + 端口，隐私性更好。CORS 预检请求必带 Origin。POST / iframe 等场景也会带。</li><li>区别： <ul><li>Origin 是 whatwg / CORS 引入，跨域场景更规范。</li><li>Referer 在从 HTTPS 到 HTTP 的跳转、或用 <code>Referrer-Policy</code> 收紧时可能为空或只带 origin。</li><li>现代浏览器默认 <code>Referrer-Policy: strict-origin-when-cross-origin</code>：同源发完整 Referer，跨域只发 origin。</li></ul></li><li>安全场景建议校验 Origin（更可靠），Referer 只作辅助。</li></ul><h2 id="追问-3-怎么用-curl-完整看到请求和响应报文" tabindex="-1">追问 3：怎么用 curl 完整看到请求和响应报文？ <a class="header-anchor" href="#追问-3-怎么用-curl-完整看到请求和响应报文" aria-label="Permalink to &quot;追问 3：怎么用 curl 完整看到请求和响应报文？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>常用命令：</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 打印详细头信息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/api</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 只输出响应头（HEAD 请求）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 打印请求头 + 响应头 + 响应体</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSv</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/null</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 手动构造 POST + JSON body</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/api</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;name&quot;:&quot;foo&quot;}&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 显示计时（DNS / 连接 / TLS / TTFB / 总耗时）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;@curl-format.txt&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/null</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><ul><li><code>curl-format.txt</code> 可写：</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>time_namelookup:  %{time_namelookup}\\n</span></span>
<span class="line"><span>time_connect:     %{time_connect}\\n</span></span>
<span class="line"><span>time_appconnect:  %{time_appconnect}\\n</span></span>
<span class="line"><span>time_starttransfer: %{time_starttransfer}\\n</span></span>
<span class="line"><span>time_total:       %{time_total}\\n</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>排查线上问题时，<code>curl -v --trace-ascii</code> 打印完整字节；<code>curl --http2</code> / <code>--http3</code> 指定协议。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc9110.html" target="_blank" rel="noreferrer">RFC 9110: HTTP Semantics</a>：报文结构与头字段规范</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Guides/Messages" target="_blank" rel="noreferrer">MDN: HTTP messages</a>：请求/响应报文组成</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers" target="_blank" rel="noreferrer">MDN: HTTP headers</a>：常见 Header 参考</li></ul>`,30)])])}const k=e(i,[["render",r]]);export{u as __pageData,k as default};
